+import * as fs from "node:fs";
+
+type ToolCall = {
+  name: "read_file";
+  args: {
+    file_path: string;
+  };
+};
+
+type Message = {
+  role: "system" | "user" | "assistant" | "tool";
+  content: string | null;
+  tool_call?: ToolCall;
+  tool_call_id?: string;
+};
+
+function fakeModel(messages: Message[]): Message {
+  const last = messages[messages.length - 1];
+
+  // 第一次：看到用户问题，先请求工具
+  if (last.role === "user") {
+    return {
+      role: "assistant",
+      tool_call: {
+        name: "read_file",
+        args: { file_path: "package.json" },
+      },
+      content: null,
+    };
+  }
+
+  // 第二次：收到工具结果后，给最终回答
+  if (last.role === "tool") {
+    const text = last.content || "";
+    let name = "未知";
+
+    try {
+      const obj = JSON.parse(text) as { name?: string };
+      name = obj.name || "未知";
+    } catch {
+      // 这里忽略 JSON 解析失败，保持默认值即可
+    }
+
+    return {
+      role: "assistant",
+      content: `我已读取 package.json，项目名是：${name}`,
+    };
+  }
+
+  return { role: "assistant", content: "我不知道该做什么" };
+}
+
+function runTool(toolCall: ToolCall): string {
+  if (toolCall.name !== "read_file") {
+    return "错误：未知工具";
+  }
+
+  const p = toolCall.args.file_path;
+
+  try {
+    return fs.readFileSync(p, "utf-8");
+  } catch (error) {
+    const message = error instanceof Error ? error.message : String(error);
+    return `读取失败: ${message}`;
+  }
+}
+
+function main(): void {
+  const messages: Message[] = [
+    { role: "system", content: "你是一个会调用工具的助手" },
+    { role: "user", content: "读取 package.json 并告诉我项目名" },
+  ];
+
+  for (let i = 0; i < 5; i++) {
+    const assistant = fakeModel(messages);
+    messages.push(assistant);
+
+    if (!assistant.tool_call) {
+      console.log("最终回答:", assistant.content);
+      break;
+    }
+
+    console.log("模型请求工具:", assistant.tool_call);
+    const result = runTool(assistant.tool_call);
+    messages.push({
+      role: "tool",
+      tool_call_id: "call_1",
+      content: result,
+    });
+    console.log("工具执行完成，结果长度:", result.length);
+  }
+}
+
+main();
